  business_line_order = {"electronics" => 0, "grocery" => 1, "pharmacy" => 2, "restaurant" => 3}

  valid_coupons = [] of {String, String}

  code.each_with_index do |c, i|
    next if c.empty?
    next unless c.each_char.all? { |ch| ch.ascii_alphanumeric? || ch == '_' }
    next unless valid_business_lines.includes?(businessLine[i])
    next unless isActive[i]

    valid_coupons << {businessLine[i], c}
  end

  valid_coupons.sort_by! do |bl, c|
    {business_line_order[bl], c}
  end

  valid_coupons.map { |_, c| c }
end
